import{_ as a,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Solução 429: Rotação de Conta e Tratamento de Erro | Antigravity-Manager","description":"Aprenda método de solução de erro 429 do Antigravity Tools. Domine identificação e tratamento de erros QUOTA_EXHAUSTED, RATE_LIMIT_EXCEEDED, etc, use Monitor e X-Account-Email para localizar rapidamente problemas.","frontmatter":{"title":"Solução 429: Rotação de Conta e Tratamento de Erro | Antigravity-Manager","sidebarTitle":"Erro 429: Rotação Automática de Conta","subtitle":"Solução 429: Rotação de Conta e Tratamento de Erro","description":"Aprenda método de solução de erro 429 do Antigravity Tools. Domine identificação e tratamento de erros QUOTA_EXHAUSTED, RATE_LIMIT_EXCEEDED, etc, use Monitor e X-Account-Email para localizar rapidamente problemas.","tags":["FAQ","Solução de Erro","Agendamento de Conta","Erro 429"],"prerequisite":["start-getting-started","advanced-scheduling"],"order":3},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"}'),i={name:"pt/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"};function s(n,e,d,c,l,m){return t(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="_429-erro-de-capacidade-previsao-correta-de-rotacao-de-conta-e-equivoco-de-exaustao-de-capacidade-de-modelo" tabindex="-1">429/Erro de Capacidade: Previsão Correta de Rotação de Conta e Equívoco de Exaustão de Capacidade de Modelo <a class="header-anchor" href="#_429-erro-de-capacidade-previsao-correta-de-rotacao-de-conta-e-equivoco-de-exaustao-de-capacidade-de-modelo" aria-label="Permalink to &quot;429/Erro de Capacidade: Previsão Correta de Rotação de Conta e Equívoco de Exaustão de Capacidade de Modelo&quot;">​</a></h1><h2 id="o-que-voce-podera-fazer-apos-completar" tabindex="-1">O que você poderá fazer após completar <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-completar" aria-label="Permalink to &quot;O que você poderá fazer após completar&quot;">​</a></h2><ul><li>Distinguir corretamente 「Cota insuficiente」 e 「Limitação de taxa upstream」, evitar julgamento errado</li><li>Entender mecanismo automático de rotação e comportamento esperado do Antigravity Tools</li><li>Ao encontrar erro 429, saber como localizar rapidamente problema e otimizar configuração</li></ul><h2 id="seu-dilema-atual" tabindex="-1">Seu dilema atual <a class="header-anchor" href="#seu-dilema-atual" aria-label="Permalink to &quot;Seu dilema atual&quot;">​</a></h2><ul><li>Ao ver erro 429, erroneamente pensar que &quot;modelo não tem capacidade&quot;</li><li>Configurou múltiplas contas, mas ainda encontra frequentemente 429, não sabe se é problema de configuração ou de conta</li><li>Não sabe quando sistema automaticamente troca de conta, quando &quot;trava&quot;</li></ul><h2 id="ideia-principal" tabindex="-1">Ideia principal <a class="header-anchor" href="#ideia-principal" aria-label="Permalink to &quot;Ideia principal&quot;">​</a></h2><h3 id="o-que-e-erro-429" tabindex="-1">O que é erro 429? <a class="header-anchor" href="#o-que-e-erro-429" aria-label="Permalink to &quot;O que é erro 429?&quot;">​</a></h3><p><strong>429 Too Many Requests</strong> é código de status HTTP. No Antigravity Tools, 429 não só representa &quot;solicitações muito frequentes&quot;, mas também pode ser cota esgotada, modelo temporariamente sobrecarregado, etc., um tipo de sinal &quot;você temporariamente não consegue usar&quot;.</p><div class="info custom-block"><p class="custom-block-title">Proxy tentará identificar causa de 429</p><p>Proxy tentará analisar <code>error.details[0].reason</code> ou <code>error.message</code> do corpo de resposta, classificar 429 em algumas categorias (efetivamente baseado no retorno):</p><table tabindex="0"><thead><tr><th>Tipo identificado pelo proxy</th><th>Razão comum / Busca</th><th>Característica típica</th></tr></thead><tbody><tr><td><strong>Cota esgotada</strong></td><td><code>QUOTA_EXHAUSTED</code> / texto contém <code>exhausted</code>, <code>quota</code></td><td>Pode precisar esperar cota atualizar</td></tr><tr><td><strong>Limitação de taxa</strong></td><td><code>RATE_LIMIT_EXCEEDED</code> / texto contém <code>per minute</code>, <code>rate limit</code>, <code>too many requests</code></td><td>Geralmente resfriamento de nível de dezenas de segundos</td></tr><tr><td><strong>Capacidade de modelo insuficiente</strong></td><td><code>MODEL_CAPACITY_EXHAUSTED</code> / texto contém <code>model_capacity</code></td><td>Geralmente sobrecarga breve, pode recuperar depois</td></tr><tr><td><strong>Desconhecido</strong></td><td>Não consegue analisar</td><td>Usa estratégia de resfriamento padrão</td></tr></tbody></table></div><h3 id="tratamento-automatico-do-antigravity-tools" tabindex="-1">Tratamento automático do Antigravity Tools <a class="header-anchor" href="#tratamento-automatico-do-antigravity-tools" aria-label="Permalink to &quot;Tratamento automático do Antigravity Tools&quot;">​</a></h3><p>Quando uma solicitação encontra 429 (e alguns estados de sobrecarga 5xx), proxy geralmente fará duas coisas no lado do servidor:</p><ol><li><strong>Registrar tempo de resfriamento</strong>: escrever este erro em <code>RateLimitTracker</code>, ao selecionar conta subsequentemente evitará ativamente &quot;ainda em resfriamento&quot; contas.</li><li><strong>Rotacionar contas em retries</strong>: Handlers realizarão múltiplas tentativas dentro de uma única solicitação, ao retry <code>force_rotate=true</code>, disparando TokenManager para selecionar próxima conta disponível.</li></ol><div class="tip custom-block"><p class="custom-block-title">Como você sabe se ele trocou de conta?</p><p>Mesmo se seu corpo de solicitação não mudar, resposta geralmente virá com <code>X-Account-Email</code> (e <code>X-Mapped-Model</code>), você pode usá-lo para verificar &quot;esta solicitação exatamente usou qual conta&quot;.</p></div><h2 id="quando-encontrara-erro-429" tabindex="-1">Quando encontrará erro 429? <a class="header-anchor" href="#quando-encontrara-erro-429" aria-label="Permalink to &quot;Quando encontrará erro 429?&quot;">​</a></h2><h3 id="cenario-1-solicitacoes-individuais-muito-rapidas" tabindex="-1">Cenário 1: Solicitações individuais muito rápidas <a class="header-anchor" href="#cenario-1-solicitacoes-individuais-muito-rapidas" aria-label="Permalink to &quot;Cenário 1: Solicitações individuais muito rápidas&quot;">​</a></h3><p><strong>Fenômeno</strong>: mesmo com apenas uma conta, enviar muitas solicitações em pouco tempo também disparará 429.</p><p><strong>Causa</strong>: cada conta tem sua própria limitação de taxa (RPM/TPM), excederá limitação.</p><p><strong>Solução</strong>:</p><ul><li>Aumentar número de contas</li><li>Reduzir frequência de solicitação</li><li>Usar modo de conta fixa dispersar pressão (veja 「Modo de Conta Fixa」)</li></ul><h3 id="cenario-2-todas-contas-simultaneamente-limitadas" tabindex="-1">Cenário 2: Todas contas simultaneamente limitadas <a class="header-anchor" href="#cenario-2-todas-contas-simultaneamente-limitadas" aria-label="Permalink to &quot;Cenário 2: Todas contas simultaneamente limitadas&quot;">​</a></h3><p><strong>Fenômeno</strong>: tem múltiplas contas, mas todas as contas retornam 429.</p><p><strong>Causa</strong>:</p><ul><li>Número total de contas insuficiente para suportar sua frequência de solicitações</li><li>Todas contas quase simultaneamente dispararam limitação/sobrecarga</li></ul><p><strong>Solução</strong>:</p><ul><li>Adicionar mais contas</li><li>Ajustar modo de agendamento para 「Prioridade de Desempenho」 (pular sessão aderente e reuso de 60s de janela)</li><li>Verificar se proteção de cota erroneamente excluiu contas disponíveis</li></ul><h3 id="cenario-3-conta-erroneamente-julgada-por-protecao-de-cota" tabindex="-1">Cenário 3: Conta erroneamente julgada por proteção de cota <a class="header-anchor" href="#cenario-3-conta-erroneamente-julgada-por-protecao-de-cota" aria-label="Permalink to &quot;Cenário 3: Conta erroneamente julgada por proteção de cota&quot;">​</a></h3><p><strong>Fenômeno</strong>: cota de certa conta é muito suficiente, mas sistema sempre a pula.</p><p><strong>Causa</strong>:</p><ul><li>Habilitou <strong>Proteção de Cota</strong>, limite definido muito alto</li><li>Cota de modelo específico desta conta é abaixo do limite</li><li>Conta foi marcada manualmente como <code>proxy_disabled</code></li></ul><p><strong>Solução</strong>:</p><ul><li>Verificar configuração de proteção de cota (Settings → Quota Protection), ajustar limite e modelos monitorados conforme sua intensidade de uso</li><li>Nos dados de conta verificar <code>protected_models</code>, confirmar se foi pulada por estratégia de proteção</li></ul><h2 id="siga-me" tabindex="-1">Siga-me <a class="header-anchor" href="#siga-me" aria-label="Permalink to &quot;Siga-me&quot;">​</a></h2><h3 id="passo-1-identificar-tipo-de-erro-429" tabindex="-1">Passo 1: Identificar tipo de erro 429 <a class="header-anchor" href="#passo-1-identificar-tipo-de-erro-429" aria-label="Permalink to &quot;Passo 1: Identificar tipo de erro 429&quot;">​</a></h3><p><strong>Por que</strong>: Diferentes tipos de erro 429 precisam de diferentes maneiras de tratamento.</p><p>No Proxy Monitor veja corpo de resposta de erro 429, foque em duas categorias de informação:</p><ul><li><strong>Causa</strong>: <code>error.details[0].reason</code> (ex: <code>RATE_LIMIT_EXCEEDED</code>, <code>QUOTA_EXHAUSTED</code>) ou <code>error.message</code></li><li><strong>Tempo de espera</strong>: <code>RetryInfo.retryDelay</code> ou <code>details[0].metadata.quotaResetDelay</code> (se existir)</li></ul><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;RATE_LIMIT_EXCEEDED&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;metadata&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          &quot;quotaResetDelay&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;42s&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Você deve ver</strong>:</p><ul><li>Se no corpo de resposta consegue encontrar tempo de espera (ex: <code>RetryInfo.retryDelay</code> ou <code>quotaResetDelay</code>), proxy geralmente primeiro espera um curto período depois retry.</li><li>Se não tem tempo de espera, proxy dará a esta conta um &quot;período de resfriamento&quot; segundo estratégia interna, e no retry diretamente trocar próxima conta.</li></ul><h3 id="passo-2-verificar-configuracao-de-agendamento-de-conta" tabindex="-1">Passo 2: Verificar configuração de agendamento de conta <a class="header-anchor" href="#passo-2-verificar-configuracao-de-agendamento-de-conta" aria-label="Permalink to &quot;Passo 2: Verificar configuração de agendamento de conta&quot;">​</a></h3><p><strong>Por que</strong>: Configuração de agendamento afeta diretamente frequência e prioridade de rotação de conta.</p><p>Entre na página <strong>API Proxy</strong>, verifique estratégia de agendamento:</p><table tabindex="0"><thead><tr><th>Item de configuração</th><th>Descrição</th><th>Padrão/Sugestão</th></tr></thead><tbody><tr><td><strong>Scheduling Mode</strong></td><td>Modo de agendamento</td><td><code>Balance</code> (padrão)</td></tr><tr><td><strong>Preferred Account</strong></td><td>Modo de conta fixa</td><td>Não selecionado (padrão)</td></tr></tbody></table><p><strong>Comparação de modos de agendamento</strong>:</p><table tabindex="0"><thead><tr><th>Modo</th><th>Estratégia de reuso de conta</th><th>Tratamento de limitação</th><th>Cenário aplicável</th></tr></thead><tbody><tr><td><strong>CacheFirst</strong></td><td>Habilitar sessão aderente e reuso de 60s de janela</td><td><strong>Priorizar espera</strong>, melhora muito taxa de acerto de Prompt Caching</td><td>Conversacional/necessita alta taxa de acerto de cache</td></tr><tr><td><strong>Balance</strong></td><td>Habilitar sessão aderente e reuso de 60s de janela</td><td><strong>Trocar imediatamente</strong> para conta alternativa, equilibra sucesso e desempenho</td><td>Cenário geral, padrão</td></tr><tr><td><strong>PerformanceFirst</strong></td><td>Pular sessão aderente e reuso de 60s de janela, modo puro de polling</td><td>Trocar imediatamente, carga de conta mais equilibrada</td><td>Alta concorrência, solicitações sem estado</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Cache priorizado vs modo balance</p><p>Se você usa Prompt Caching e quer melhorar taxa de acerto de cache, escolha <code>CacheFirst</code> — ao limitar, ele priorizará esperar em vez de trocar imediatamente. Se você se importa mais com taxa de sucesso de solicitação do que cache, escolha <code>Balance</code> — ao limitar, ele trocará imediatamente.</p></div><div class="tip custom-block"><p class="custom-block-title">Modo prioridade de desempenho</p><p>Se suas solicitações são sem estado (ex: geração de imagem, consulta independente), pode tentar <code>PerformanceFirst</code>. Ele pulará sessão aderente e reuso de 60s de janela, facilitando solicitações consecutivas caírem em contas diferentes.</p></div><h3 id="passo-3-verificar-se-rotacao-de-conta-funciona-normalmente" tabindex="-1">Passo 3: Verificar se rotação de conta funciona normalmente <a class="header-anchor" href="#passo-3-verificar-se-rotacao-de-conta-funciona-normalmente" aria-label="Permalink to &quot;Passo 3: Verificar se rotação de conta funciona normalmente&quot;">​</a></h3><p><strong>Por que</strong>: Confirmar sistema consegue alternar automaticamente contas.</p><p><strong>Método 1: Ver cabeçalho de resposta</strong></p><p>Use curl ou seu próprio cliente para imprimir cabeçalhos de resposta, observe se <code>X-Account-Email</code> muda.</p><p><strong>Método 2: Ver logs</strong></p><p>Abra arquivo de log (conforme localização do seu sistema), pesquise <code>🔄 [Token Rotation]</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔄 [Token Rotation] Accounts: [</span></span>
<span class="line"><span>  &quot;account1@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account2@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account3@example.com(protected=[])&quot;</span></span>
<span class="line"><span>]</span></span></code></pre></div><p><strong>Método 3: Usar Proxy Monitor</strong></p><p>Na página <strong>Monitor</strong> veja logs de solicitação, foque em:</p><ul><li>Campo <strong>Account</strong> muda entre diferentes contas</li><li>Após solicitação com <strong>Status</strong> 429, se há solicitação bem-sucedida usando conta diferente</li></ul><p><strong>Você deve ver</strong>:</p><ul><li>Após certa conta retornar 429, solicitações subsequentes automaticamente trocam para outras contas</li><li>Se vê múltiplas solicitações usando mesma conta e todas falhando, pode ser problema de configuração de agendamento</li></ul><h3 id="passo-4-otimizar-prioridade-de-conta" tabindex="-1">Passo 4: Otimizar prioridade de conta <a class="header-anchor" href="#passo-4-otimizar-prioridade-de-conta" aria-label="Permalink to &quot;Passo 4: Otimizar prioridade de conta&quot;">​</a></h3><p><strong>Por que</strong>: Fazer sistema priorizar usar conta de cota alta/nível alto, reduzir probabilidade de 429.</p><p>No TokenManager, sistema fará uma ordenação no pool de contas antes de selecionar conta (imprimirá <code>🔄 [Token Rotation] Accounts: ...</code>):</p><ol><li><strong>Prioridade de nível de assinatura</strong>: UTRA &gt; PRO &gt; FREE</li><li><strong>Prioridade de porcentagem de cota</strong>: dentro do mesmo nível, cota alta na frente</li><li><strong>Entrada de ordenação</strong>: esta ordenação acontece no lado do proxy, qual conta finalmente usar baseia na ordenação do lado do proxy + julgamento de disponibilidade.</li></ol><div class="info custom-block"><p class="custom-block-title">Princípio de ordenação inteligente (lado do proxy)</p><p>Prioridade é <code>ULTRA &gt; PRO &gt; FREE</code>; dentro do mesmo nível de assinatura por <code>remaining_quota</code> (porcentagem de cota restante máxima da conta) decrescente.</p></div><p><strong>Operação</strong>:</p><ul><li>Arraste conta para ajustar ordem de exibição (opcional)</li><li>Atualizar cota (Accounts → Atualizar todas as cotas)</li><li>Ver nível de assinatura e cota da conta</li></ul><h2 id="aviso-sobre-armadilhas" tabindex="-1">Aviso sobre armadilhas <a class="header-anchor" href="#aviso-sobre-armadilhas" aria-label="Permalink to &quot;Aviso sobre armadilhas&quot;">​</a></h2><h3 id="❌-erro-1-erroneamente-tratar-429-como-modelo-sem-capacidade" tabindex="-1">❌ Erro 1: Erroneamente tratar 429 como &quot;modelo sem capacidade&quot; <a class="header-anchor" href="#❌-erro-1-erroneamente-tratar-429-como-modelo-sem-capacidade" aria-label="Permalink to &quot;❌ Erro 1: Erroneamente tratar 429 como &quot;modelo sem capacidade&quot;&quot;">​</a></h3><p><strong>Fenômeno</strong>: Ao ver erro 429, acha que modelo sem capacidade.</p><p><strong>Compreensão correta</strong>:</p><ul><li>429 é <strong>limitação</strong>, não problema de capacidade</li><li>Aumentar contas pode reduzir probabilidade de 429</li><li>Ajustar modo de agendamento pode melhorar velocidade de troca</li></ul><h3 id="❌-erro-2-limite-de-protecao-de-cota-definido-muito-alto" tabindex="-1">❌ Erro 2: Limite de proteção de cota definido muito alto <a class="header-anchor" href="#❌-erro-2-limite-de-protecao-de-cota-definido-muito-alto" aria-label="Permalink to &quot;❌ Erro 2: Limite de proteção de cota definido muito alto&quot;">​</a></h3><p><strong>Fenômeno</strong>: Cota suficiente mas sistema sempre pula conta.</p><p><strong>Causa</strong>: Quota Protection adiciona modelos abaixo do limite ao <code>protected_models</code> da conta, proxy no agendamento pulará &quot;modelos protegidos&quot;. Limite muito alto pode causar contas disponíveis serem excessivamente excluídas.</p><p><strong>Correção</strong>:</p><ul><li>Volte para <strong>Settings → Quota Protection</strong>, ajuste modelos monitorados e limite</li><li>Se você quer entender quais modelos exatamente são protegidos, vá nos dados de conta ver <code>protected_models</code></li></ul><h3 id="❌-erro-3-modo-de-conta-fixa-leva-a-impossibilidade-de-rotacao" tabindex="-1">❌ Erro 3: Modo de conta fixa leva a impossibilidade de rotação <a class="header-anchor" href="#❌-erro-3-modo-de-conta-fixa-leva-a-impossibilidade-de-rotacao" aria-label="Permalink to &quot;❌ Erro 3: Modo de conta fixa leva a impossibilidade de rotação&quot;">​</a></h3><p><strong>Fenômeno</strong>: Configurou <code>Preferred Account</code>, mas sistema &quot;trava&quot; quando essa conta limita.</p><p><strong>Causa</strong>: No modo de conta fixa, sistema prioriza usar conta especificada, só degrada para polling quando conta não disponível.</p><p><strong>Correção</strong>:</p><ul><li>Se não precisa de conta fixa, esvazie <code>Preferred Account</code></li><li>Ou garanta cota suficiente de conta fixa, evitar limitação</li></ul><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de verificação ✅&quot;">​</a></h2><ul><li>[ ] Consegue distinguir cota insuficiente e limitação de taxa upstream</li><li>[ ] Sabe como ver detalhes de erro 429 no Proxy Monitor</li><li>[ ] Entende diferença entre três modos de agendamento e cenários de uso</li><li>[ ] Sabe como verificar se rotação de conta funciona normalmente</li><li>[ ] Consegue otimizar prioridade de conta e verificar estratégia de proteção de cota</li></ul><h2 id="perguntas-comuns" tabindex="-1">Perguntas comuns <a class="header-anchor" href="#perguntas-comuns" aria-label="Permalink to &quot;Perguntas comuns&quot;">​</a></h2><h3 id="q1-por-que-tenho-multiplas-contas-ainda-encontro-429" tabindex="-1">Q1: Por que tenho múltiplas contas, ainda encontro 429? <a class="header-anchor" href="#q1-por-que-tenho-multiplas-contas-ainda-encontro-429" aria-label="Permalink to &quot;Q1: Por que tenho múltiplas contas, ainda encontro 429?&quot;">​</a></h3><p>A: Causas possíveis:</p><ol><li>Todas contas simultaneamente dispararam limitação (frequência de solicitações muito alta)</li><li>Solicitações consecutivas em &quot;reuso de 60s de janela&quot; repetidamente reusam mesma conta, mais fácil jogar conta única para limitação</li><li>Proteção de cota erroneamente excluiu contas disponíveis</li><li>Número total de contas insuficiente para suportar sua frequência de solicitações</li></ol><p><strong>Solução</strong>:</p><ul><li>Adicionar mais contas</li><li>Usar modo <code>PerformanceFirst</code></li><li>Verificar se Quota Protection adicionou modelos que você usa ao <code>protected_models</code> (se necessário ajustar modelos monitorados e limite)</li><li>Reduzir frequência de solicitações</li></ul><h3 id="q2-erro-429-sera-automaticamente-retry" tabindex="-1">Q2: Erro 429 será automaticamente retry? <a class="header-anchor" href="#q2-erro-429-sera-automaticamente-retry" aria-label="Permalink to &quot;Q2: Erro 429 será automaticamente retry?&quot;">​</a></h3><p>A: Retryará automaticamente dentro de uma única solicitação. <strong>Limite superior de número de retry geralmente é 3 vezes</strong>, método de cálculo específico é <code>min(3, tamanho do pool de contas)</code>, e pelo menos tentar 1 vez.</p><p><strong>Exemplo de número de retries</strong>:</p><ul><li>Pool de contas 1 conta → tentar 1 vez (sem retry)</li><li>Pool de contas 2 contas → tentar 2 vezes (retry 1 vez)</li><li>Pool de contas 3 ou mais contas → tentar 3 vezes (retry 2 vezes)</li></ul><p><strong>Fluxo aproximado</strong>:</p><ol><li>Registrar informação de limitação/sobrecarga (entrar em <code>RateLimitTracker</code>)</li><li>Se consegue analisar tempo de espera (ex: <code>RetryInfo.retryDelay</code> / <code>quotaResetDelay</code>), primeiro espera um curto período depois continua</li><li>Ao retry força rotação de conta (<code>attempt &gt; 0</code> <code>force_rotate=true</code>), tentar usar próxima conta disponível iniciar solicitação upstream</li></ol><p>Se todas as tentativas falharem, proxy retornará erro ao cliente; ao mesmo tempo você ainda pode nos cabeçalhos de resposta (como <code>X-Account-Email</code>) ou Proxy Monitor ver contas realmente usadas.</p><h3 id="q3-como-ver-por-quanto-tempo-certa-conta-foi-limitada" tabindex="-1">Q3: Como ver por quanto tempo certa conta foi limitada? <a class="header-anchor" href="#q3-como-ver-por-quanto-tempo-certa-conta-foi-limitada" aria-label="Permalink to &quot;Q3: Como ver por quanto tempo certa conta foi limitada?&quot;">​</a></h3><p>A: Há duas maneiras:</p><p><strong>Método 1</strong>: Ver logs, pesquisar <code>rate-limited</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔧 [FIX #820] Preferred account xxx@gmail.com is rate-limited, falling back to round-robin</span></span></code></pre></div><p><strong>Método 2</strong>: Logs mostrarão tempo de espera restante</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>All accounts are currently limited. Please wait 30s.</span></span></code></pre></div><h3 id="q4-protecao-de-cota-e-limitacao-sao-a-mesma-coisa" tabindex="-1">Q4: Proteção de cota e limitação são a mesma coisa? <a class="header-anchor" href="#q4-protecao-de-cota-e-limitacao-sao-a-mesma-coisa" aria-label="Permalink to &quot;Q4: Proteção de cota e limitação são a mesma coisa?&quot;">​</a></h3><p>A: Não são.</p><table tabindex="0"><thead><tr><th>Característica</th><th>Proteção de cota</th><th>Rastreamento de limitação</th></tr></thead><tbody><tr><td><strong>Condição de disparo</strong></td><td>Cota de modelo abaixo do limite</td><td>Recebeu erro 429</td></tr><tr><td><strong>Escopo de ação</strong></td><td>Modelo específico</td><td>Conta inteira</td></tr><tr><td><strong>Duração</strong></td><td>Até cota recuperar</td><td>Decidido por upstream (geralmente poucos segundos a minutos)</td></tr><tr><td><strong>Comportamento</strong></td><td>Pular este modelo</td><td>Pular esta conta</td></tr></tbody></table><h3 id="q5-como-forcar-troca-imediata-de-conta" tabindex="-1">Q5: Como forçar troca imediata de conta? <a class="header-anchor" href="#q5-como-forcar-troca-imediata-de-conta" aria-label="Permalink to &quot;Q5: Como forçar troca imediata de conta?&quot;">​</a></h3><p>A: Pode começar do ângulo &quot;facilitar próxima solicitação trocar de conta&quot;:</p><ol><li><strong>Nível de agendamento</strong>: mude para <code>PerformanceFirst</code>, pular sessão aderente e reuso de 60s de janela</li><li><strong>Conta fixa</strong>: se habilitou <code>Preferred Account</code>, primeiro esvazie, caso contrário priorizará usar conta fixa (até ela limitar/ser protegida)</li><li><strong>Pool de contas</strong>: aumentar número de contas, quando conta única for limitada mais fácil encontrar conta alternativa</li></ol><p>Dentro de uma única solicitação, proxy também forçará rotação ao retry (<code>attempt &gt; 0</code> disparará <code>force_rotate=true</code>), mas número de retries é limitado por limite superior.</p><h2 id="resumo-da-licao" tabindex="-1">Resumo da lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da lição&quot;">​</a></h2><ul><li>429 no Antigravity Tools é um tipo de sinal &quot;upstream temporariamente não disponível&quot;, pode ser limitação de taxa, cota esgotada, capacidade de modelo insuficiente etc.</li><li>Proxy registrará tempo de resfriamento, e tentará rotacionar contas nos retries de uma única solicitação (mas número de retries é limitado)</li><li>Modo de agendamento, Quota Protection, número de contas todos afetam probabilidade e velocidade de recuperação de encontrar 429</li><li>Use Proxy Monitor, cabeçalho de resposta <code>X-Account-Email</code> e logs podem localizar rapidamente problemas</li></ul><h2 id="proximo-aviso-de-licao" tabindex="-1">Próximo aviso de lição <a class="header-anchor" href="#proximo-aviso-de-licao" aria-label="Permalink to &quot;Próximo aviso de lição&quot;">​</a></h2><blockquote><p>Na próxima lição aprendemos <strong><a href="./../404-base-url/">404/Rota Incompatível: Base URL, Prefixo /v1 e Cliente &quot;Caminho Sobreposto&quot;</a></strong>.</p><p>Você aprenderá:</p><ul><li>Como erro de integração mais comum (404) é produzido</li><li>Diferença de concatenação de base_url de diferentes clientes</li><li>Como corrigir rapidamente problemas de 404</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">Apêndice: Referência de código-fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência de código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir localização do código-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Linha</th></tr></thead><tbody><tr><td>Análise de delay de retry 429 (RetryInfo / quotaResetDelay)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L38-L67" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>38-67</td></tr><tr><td>Ferramenta de análise de Duration</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L11-L35" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>11-35</td></tr><tr><td>Enumeração de modo de agendamento (CacheFirst/Balance/PerformanceFirst)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/sticky_config.rs#L3-L12" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/sticky_config.rs</code></a></td><td>3-12</td></tr><tr><td>Análise de razão de limitação e estratégia de resfriamento padrão</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/rate_limit.rs#L5-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/rate_limit.rs</code></a></td><td>5-258</td></tr><tr><td>Definição de constante MAX_RETRY_ATTEMPTS (handler OpenAI)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L14" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>14</td></tr><tr><td>Cálculo de número de retries (max_attempts = min(MAX_RETRY_ATTEMPTS, pool_size))</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L830" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>830</td></tr><tr><td>Handler OpenAI: marca limitação e retry/rotação ao 429/5xx</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L349-L389" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>349-389</td></tr><tr><td>Prioridade de ordenação de conta (ULTRA &gt; PRO &gt; FREE + remaining_quota)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L504-L538" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>504-538</td></tr><tr><td>Reuso de janela de 60s + evitar limitação/proteção de cota</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L624-L739" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>624-739</td></tr><tr><td>Entrada de registro de limitação (mark_rate_limited)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1089-L1113" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1089-1113</td></tr><tr><td>Bloqueio preciso de 429/atualização de cota em tempo real/estratégia de downgrade (mark_rate_limited_async)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1258-L1417" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1258-1417</td></tr></tbody></table><p><strong>Constantes principais</strong>:</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code>: número máximo de retries dentro de uma única solicitação (handler OpenAI/Gemini)</li><li><code>60</code>: reuso de janela de 60 segundos (só habilitado em modos fora <code>PerformanceFirst</code>)</li><li><code>5</code>: tempo limite de obtenção de token (segundos)</li><li><code>300</code>: limite de pré-atualização de token (segundos, 5 minutos)</li></ul><p><strong>Funções principais</strong>:</p><ul><li><code>parse_retry_delay()</code>: extrair delay de retry de resposta de erro 429</li><li><code>get_token_internal()</code>: lógica principal de seleção e rotação de conta</li><li><code>mark_rate_limited()</code>: marcar conta como estado limitado</li></ul></details>`,116)])])}const g=a(i,[["render",s]]);export{u as __pageData,g as default};
